const express = require('express');
const app = express();

app.get('/', (req, res) => {
  res.send('<h1>Hello from Render!</h1><p>Deployed via deployment worker 🚀</p>');
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
